import { createGlobalStyle } from "styled-components";

/**
 * Global styles with Meta-inspired design system variables
 */
const GlobalStyles = createGlobalStyle`
  :root {
    /* Primary colors */
    --primary-color: #0668E1;
    --secondary-color: #0077FA;
    --accent-color: #00B5E2;

