    --text-tertiary: #718096;
    --text-light: #FFFFFF;

    /* Background colors */
    --background-white: #FFFFFF;
    --background-light: #F7F8FB;
    --background-medium: #E4E6EB;
    --background-dark: #1C2B33;

    /* Border colors */
    --border-color: #E4E6EB;
    --border-light: #F0F2F5;

    /* Spacing variables - using 4px as base unit */
